-- Per-language translations of `matches.story`. Source story stays
-- in `matches.story` (Vietnamese); this table holds en/th/zh/ko
-- translations generated by Qwen-Plus-Latest on demand.
--
-- One row per (match_id, lang). Idempotent insert via the unique
-- constraint; daily cron picks up missing rows and fills them in.
CREATE TABLE IF NOT EXISTS match_story_translations (
    id            BIGSERIAL PRIMARY KEY,
    match_id      INTEGER NOT NULL REFERENCES matches(id) ON DELETE CASCADE,
    lang          TEXT NOT NULL,
    story         TEXT NOT NULL,
    model         TEXT,
    translated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (match_id, lang)
);

CREATE INDEX IF NOT EXISTS idx_story_trans_match_lang
    ON match_story_translations (match_id, lang);
